function getElementTextLabel(element: ReactElement<HoverTriggerElementProps>): string | undefined {
  const children = element.props.children;
  if (typeof children === "string" || typeof children === "number") return String(children);
  return undefined;
}

export function PopoverTrigger({
  children,
  className,
  ref,
}: PopoverTriggerProps) {
  const {
    triggerRef,
    popoverId,
    open,
    triggerMode,
    onOpenChange,
    onTriggerEnter,
    onTriggerLeave,
    onTriggerClick,
    enabled,
  } = usePopoverContext();

  const composedRef = composeRefs(triggerRef, ref);
  const isClick = triggerMode === "click";
  const isRenderProp = typeof children === "function";
  const hoverClassName = isRenderProp ? className : cn("inline-flex", className);

  const handleHoverClick = () => {
    if (!enabled) return;
    onOpenChange(!open);
  };

  const handleHoverKeyDown: KeyboardEventHandler<HTMLElement> = (event) => {
    if (!enabled) return;
    if (event.key !== "Enter" && event.key !== " ") return;
    event.preventDefault();
    onOpenChange(!open);
  };

  const triggerProps = isClick
    ? ({
        ref: composedRef,
        className,
        "aria-expanded": open,
        "aria-haspopup": "dialog",
        "aria-controls": open ? popoverId : undefined,
        onClick: onTriggerClick,
      } satisfies PopoverTriggerRenderProps)
    : ({
        ref: composedRef,
        role: "button",
        className: hoverClassName,
        "aria-describedby": open ? popoverId : undefined,
        onMouseEnter: onTriggerEnter,
        onMouseLeave: onTriggerLeave,
        onFocus: onTriggerEnter,
        onBlur: onTriggerLeave,
        onClick: handleHoverClick,
        onKeyDown: handleHoverKeyDown,
        tabIndex: enabled ? 0 : undefined,
      } satisfies PopoverTriggerRenderProps);

  if (typeof children === "function") return <>{children(triggerProps)}</>;

  if (isValidElement<HoverTriggerElementProps>(children)) {
    const child = children as ReactElement<HoverTriggerElementProps>;
    const childRef = child.props.ref;
    const isNativeInteractive = isNativeInteractiveElement(child);
    const buttonType = child.type === "button" ? { type: child.props.type ?? "button" } : {};

    if (isClick && isNativeInteractive) {
      return cloneElement(child, {
        ...buttonType,
        ref: composeRefs(composedRef, childRef),
        className: cn(child.props.className, className),
        "aria-expanded": triggerProps["aria-expanded"],
        "aria-haspopup": triggerProps["aria-haspopup"],
        "aria-controls": triggerProps["aria-controls"],
        onClick: mergeHandlers(child.props.onClick, triggerProps.onClick, true),
      });
    }

    if (isClick) {
      const buttonProps = triggerProps satisfies ComponentPropsWithRef<"button">;
      return <button type="button" {...buttonProps}>{children}</button>;
    }

    const needsTabIndex = enabled && child.props.tabIndex === undefined && !isNativeInteractive;
    const isDisabledNative = triggerMode === "hover" && isNativeInteractive && child.props.disabled;

    if (isDisabledNative) {
      const spanProps = triggerProps satisfies ComponentPropsWithRef<"span">;
      const ariaLabel = child.props["aria-label"] ?? getElementTextLabel(child);
      return (
        <span {...spanProps} aria-label={ariaLabel}>
          {cloneElement(child, {
            className: cn(child.props.className, className),
            "aria-hidden": true,
            tabIndex: -1,
          })}
        </span>
      );
    }

    return cloneElement(child, {
      ref: composeRefs(composedRef, childRef),
      className: cn(child.props.className, className),
      role: child.props.role ?? (isNativeInteractive ? undefined : triggerProps.role),
      "aria-describedby": triggerProps["aria-describedby"],
      onClick: mergeHandlers(child.props.onClick, triggerProps.onClick, true),
      onMouseEnter: mergeHandlers(child.props.onMouseEnter, triggerProps.onMouseEnter),
      onMouseLeave: mergeHandlers(child.props.onMouseLeave, triggerProps.onMouseLeave),
      onFocus: mergeHandlers(child.props.onFocus, triggerProps.onFocus),
      onBlur: mergeHandlers(child.props.onBlur, triggerProps.onBlur),
      onKeyDown: mergeHandlers(child.props.onKeyDown, triggerProps.onKeyDown, true),
      tabIndex: needsTabIndex ? 0 : child.props.tabIndex,
    });
  }

  if (isClick) {
    const buttonProps = triggerProps satisfies ComponentPropsWithRef<"button">;
    return <button type="button" {...buttonProps}>{children}</button>;
  }

  const spanProps = triggerProps satisfies ComponentPropsWithRef<"span">;
  return <span {...spanProps}>{children}</span>;
}


"use client";

import { useRef, type ComponentPropsWithoutRef, type KeyboardEvent, type ReactNode, type Ref } from "react";
import { cn } from "@/lib/utils";
import { composeRefs } from "@/lib/compose-refs";
import { Portal } from "../shared/portal";
import { usePortalContainer } from "../shared/portal-context";
import { useEscapeKey, useOutsideClick } from "@/hooks/use-outside-click";
import { usePresence } from "@/hooks/use-presence";
import {
  useFloatingPosition,
  type FloatingSide,
  type FloatingAlign,
} from "@/hooks/use-floating-position";
import { usePopoverContext } from "./popover-context";
import { useAutoFocus } from "./use-auto-focus";
import { FOCUSABLE_SELECTOR } from "@/lib/focus";

export interface PopoverContentProps
  extends Omit<ComponentPropsWithoutRef<"div">, "children" | "id" | "role" | "style"> {
  children: ReactNode;
  side?: FloatingSide;
  align?: FloatingAlign;
  sideOffset?: number;
  alignOffset?: number;
  avoidCollisions?: boolean;
  collisionPadding?: number;
  autoFocus?: boolean;
  "aria-label"?: string;
  "aria-labelledby"?: string;
  ref?: Ref<HTMLDivElement>;
}

export function PopoverContent({
  children,
  side = "bottom",
  align = "center",
  sideOffset = 6,
  alignOffset = 0,
  avoidCollisions = true,
  collisionPadding = 8,
  className,
  autoFocus = true,
  "aria-label": ariaLabel,
  "aria-labelledby": ariaLabelledBy,
  tabIndex,
  ref,
  ...rest
}: PopoverContentProps) {
  const { open, triggerRef, popoverId, triggerMode, onOpenChange, onContentEnter, onContentLeave } =
    usePopoverContext();
  const presenceRef = useRef<HTMLDivElement>(null);
  const { present, onAnimationEnd } = usePresence({ open, ref: presenceRef });
  const { position, contentRef } = useFloatingPosition({
    triggerRef,
    open: present,
    side,
    align,
    sideOffset,
    alignOffset,
    avoidCollisions,
    collisionPadding,
  });

  const portalContainer = usePortalContainer();
  const isHover = triggerMode === "hover";
  const isClick = triggerMode === "click";

  useOutsideClick(
    contentRef,
    () => {
      onOpenChange(false);
      triggerRef.current?.focus();
    },
    open && isClick,
    [triggerRef],
  );

  useEscapeKey((e) => {
    e.stopPropagation();
    e.preventDefault();
    onOpenChange(false);
    triggerRef.current?.focus();
  }, open, { ref: contentRef, excludeRefs: [triggerRef] });

  useAutoFocus(contentRef, open && !isHover && autoFocus);

  const handleKeyDown = (e: KeyboardEvent<HTMLDivElement>) => {
    if (e.key === "Escape") {
      e.stopPropagation();
      e.preventDefault();
      onOpenChange(false);
      triggerRef.current?.focus();
      return;
    }

    if (!isClick) return;
    if (e.key !== "Tab") return;

    const el = contentRef.current;
    if (!el) return;

    const focusable = Array.from(el.querySelectorAll<HTMLElement>(FOCUSABLE_SELECTOR));
    if (focusable.length === 0) return;

    const first = focusable[0];
    const last = focusable[focusable.length - 1];

    if (e.shiftKey && document.activeElement === first) {
      e.preventDefault();
      last.focus();
    } else if (!e.shiftKey && document.activeElement === last) {
      e.preventDefault();
      first.focus();
    }
  };

  if (!present) return null;

  return (
    <Portal container={portalContainer ?? undefined}>
      <div
        {...rest}
        ref={composeRefs(presenceRef, contentRef, ref)}
        id={popoverId}
        role={isHover ? "tooltip" : "dialog"}
        aria-label={ariaLabel}
        aria-labelledby={ariaLabelledBy}
        tabIndex={tabIndex ?? (isHover ? undefined : -1)}
        data-state={open ? "open" : "closed"}
        data-side={position?.side}
        data-align={position?.align}
        onMouseEnter={isHover ? onContentEnter : undefined}
        onMouseLeave={isHover ? onContentLeave : undefined}
        onKeyDown={handleKeyDown}
        onAnimationEnd={onAnimationEnd}
        className={cn(
          "fixed z-9999",
          "data-[state=open]:animate-[slide-in_0.15s_ease-out]",
          "data-[state=closed]:animate-[slide-out_0.15s_ease-in_forwards]",
          className,
        )}
        style={
          position
            ? { top: position.y, left: position.x }
            : { visibility: "hidden", position: "fixed", top: 0, left: 0 }
        }
      >
        {children}
      </div>
    </Portal>
  );
}


"use client";

import { useCallback, useRef, useEffect } from "react";
import type { PopoverTriggerMode } from "./popover-context";

export interface UsePopoverBehaviorOptions {
  open: boolean;
  onOpenChange: (next: boolean | ((prev: boolean) => boolean)) => void;
  enabled?: boolean;
  triggerMode?: PopoverTriggerMode;
  delayMs?: number;
  closeDelayMs?: number;
}

export interface UsePopoverBehaviorReturn {
  onTriggerEnter: () => void;
  onTriggerLeave: () => void;
  onTriggerClick: () => void;
  onContentEnter: () => void;
  onContentLeave: () => void;
}

export function usePopoverBehavior({
  open,
  onOpenChange,
  enabled = true,
  triggerMode = "click",
  delayMs = 500,
  closeDelayMs = 0,
}: UsePopoverBehaviorOptions): UsePopoverBehaviorReturn {
  const openTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const closeTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const clearTimers = useCallback(() => {
    if (openTimerRef.current) {
      clearTimeout(openTimerRef.current);
      openTimerRef.current = null;
    }
    if (closeTimerRef.current) {
      clearTimeout(closeTimerRef.current);
      closeTimerRef.current = null;
    }
  }, []);

  const closePopover = useCallback(() => {
    clearTimers();
    onOpenChange(false);
  }, [clearTimers, onOpenChange]);

  const onTriggerEnter = useCallback(() => {
    if (!enabled || triggerMode !== "hover") return;
    clearTimers();
    if (delayMs <= 0) {
      onOpenChange(true);
      return;
    }
    openTimerRef.current = setTimeout(() => onOpenChange(true), delayMs);
  }, [clearTimers, delayMs, enabled, onOpenChange, triggerMode]);

  const scheduleClose = useCallback(() => {
    if (!enabled || triggerMode !== "hover") return;
    clearTimers();
    if (closeDelayMs > 0) {
      closeTimerRef.current = setTimeout(() => onOpenChange(false), closeDelayMs);
    } else {
      onOpenChange(false);
    }
  }, [clearTimers, closeDelayMs, enabled, onOpenChange, triggerMode]);

  const onTriggerClick = useCallback(() => {
    if (!enabled || triggerMode !== "click") return;
    onOpenChange(prev => !prev);
  }, [enabled, onOpenChange, triggerMode]);

  const onContentEnter = useCallback(() => {
    if (!enabled || triggerMode !== "hover") return;
    clearTimers();
  }, [clearTimers, enabled, triggerMode]);

  useEffect(() => {
    return () => clearTimers();
  }, [clearTimers]);

  useEffect(() => {
    if (!open || triggerMode !== "hover") return;
    const scrollOpts = { capture: true, passive: true } as const;
    window.addEventListener("scroll", closePopover, scrollOpts);
    window.addEventListener("resize", closePopover);
    return () => {
      window.removeEventListener("scroll", closePopover, scrollOpts);
      window.removeEventListener("resize", closePopover);
    };
  }, [closePopover, open, triggerMode]);

  useEffect(() => {
    if (!enabled) closePopover();
  }, [closePopover, enabled]);

  return {
    onTriggerEnter,
    onTriggerLeave: scheduleClose,
    onTriggerClick,
    onContentEnter,
    onContentLeave: scheduleClose,
  };
}


"use client";

import { useEffect, type RefObject } from "react";
import { FOCUSABLE_SELECTOR } from "@/lib/focus";

export function useAutoFocus(
  ref: RefObject<HTMLElement | null>,
  enabled: boolean,
): void {
  useEffect(() => {
    if (!enabled) return;
    const frame = requestAnimationFrame(() => {
      const el = ref.current;
      if (!el || el.contains(document.activeElement)) return;
      const target = el.querySelector<HTMLElement>(FOCUSABLE_SELECTOR);
      (target ?? el).focus({ preventScroll: true });
    });
    return () => cancelAnimationFrame(frame);
  }, [ref, enabled]);
}

